# Sentry SDK Configuration Reference

All options are passed to `Sentry.init()`. This reference covers every option for the JavaScript SDK family (`@sentry/browser`, `@sentry/node`, `@sentry/react`, `@sentry/nextjs`).

## Identity & Routing

```javascript
Sentry.init({
  // REQUIRED — Data Source Name identifying your project
  dsn: "https://examplePublicKey@o0.ingest.sentry.io/0",

  // Release version — links errors to source maps and commits
  release: "my-app@1.2.3",

  // Environment — filters events in the Sentry UI
  environment: "production",  // default: "production"

  // Fully disable the SDK (useful for local development)
  enabled: true,  // default: true
});
```

## Error Sampling & Filtering

```javascript
Sentry.init({
  // Sample rate for error events (0.0 to 1.0)
  sampleRate: 1.0,  // default: 1.0 (capture all errors)

  // Filter events before sending — return null to drop
  beforeSend(event, hint) {
    // Drop events from browser extensions
    if (event.exception?.values?.[0]?.stacktrace?.frames?.some(
      f => f.filename?.includes("extension://")
    )) {
      return null;
    }
    // Scrub PII from event
    if (event.user) {
      delete event.user.email;
    }
    return event;
  },

  // Drop events matching these error messages (strings or RegExp)
  ignoreErrors: [
    "ResizeObserver loop limit exceeded",
    "ResizeObserver loop completed with undelivered notifications",
    /^Network request failed$/,
    /^Loading chunk \d+ failed$/,
  ],

  // Only report errors from these script URLs
  allowUrls: [
    /https?:\/\/((cdn|www)\.)?myapp\.com/,
  ],

  // Never report errors from these script URLs
  denyUrls: [
    /extensions\//i,
    /^chrome:\/\//i,
    /^moz-extension:\/\//i,
  ],
});
```

## Performance Tracing

```javascript
Sentry.init({
  // Percentage of transactions to capture (0.0 to 1.0)
  tracesSampleRate: 0.2,  // 20% of transactions

  // Dynamic sampling function (overrides tracesSampleRate)
  tracesSampler(samplingContext) {
    // Always trace checkout
    if (samplingContext.name === "POST /api/checkout") return 1.0;
    // Never trace health checks
    if (samplingContext.name === "GET /health") return 0;
    // Default rate
    return 0.1;
  },

  // URLs to propagate trace headers to (default: same-origin)
  tracePropagationTargets: [
    "localhost",
    /^https:\/\/api\.myapp\.com/,
  ],

  // Filter transactions before sending
  beforeSendTransaction(event) {
    if (event.transaction === "/health") return null;
    return event;
  },

  // Filter specific spans
  ignoreTransactions: ["/health", /^\/internal\//],
});
```

## Session Replay

```javascript
Sentry.init({
  // Capture replays for this percentage of sessions
  replaysSessionSampleRate: 0.1,  // 10%

  // Capture replay when an error occurs (captures prior 60s)
  replaysOnErrorSampleRate: 1.0,  // 100% of error sessions

  integrations: [
    Sentry.replayIntegration({
      maskAllText: true,       // mask all text content
      blockAllMedia: true,     // block images/videos
      maskAllInputs: true,     // mask form inputs
    }),
  ],
});
```

## Breadcrumbs

```javascript
Sentry.init({
  // Maximum breadcrumbs to store (default: 100)
  maxBreadcrumbs: 50,

  // Filter or modify breadcrumbs — return null to drop
  beforeBreadcrumb(breadcrumb, hint) {
    // Drop noisy console breadcrumbs
    if (breadcrumb.category === "console" && breadcrumb.level === "debug") {
      return null;
    }
    // Redact sensitive URLs
    if (breadcrumb.category === "fetch" && breadcrumb.data?.url?.includes("/auth")) {
      breadcrumb.data.url = "[REDACTED]";
    }
    return breadcrumb;
  },
});
```

## Transport & Networking

```javascript
Sentry.init({
  // Tunnel endpoint to bypass ad blockers
  // Your server proxies requests to Sentry's ingest endpoint
  tunnel: "/sentry-tunnel",

  // Custom transport (advanced — replace the default fetch transport)
  transport: Sentry.makeFetchTransport,

  // Custom transport options
  transportOptions: {
    headers: { "X-Custom-Header": "value" },
  },
});
```

### Tunnel Endpoint

Ad blockers may block requests to `*.ingest.sentry.io`. A tunnel proxies events through your own server:

```javascript
// Express tunnel endpoint example
app.post("/sentry-tunnel", async (req, res) => {
  const envelope = req.body;
  const piece = envelope.split("\n")[0];
  const header = JSON.parse(piece);
  const dsn = new URL(header.dsn);
  const projectId = dsn.pathname.replace("/", "");
  const upstream = `https://${dsn.hostname}/api/${projectId}/envelope/`;

  await fetch(upstream, {
    method: "POST",
    body: envelope,
    headers: { "Content-Type": "application/x-sentry-envelope" },
  });
  res.status(200).end();
});
```

## Debugging

```javascript
Sentry.init({
  // Log SDK operations to the console
  debug: true,  // default: false — DISABLE in production

  // Attach stack traces to all messages (not just exceptions)
  attachStacktrace: true,  // default: false

  // Control PII collection (IP address, cookies, user data)
  sendDefaultPii: false,  // default: false
});
```

## Data Normalization

```javascript
Sentry.init({
  // Depth for walking contextual data objects (default: 3)
  normalizeDepth: 5,

  // Max properties per object/array in normalized data (default: 1000)
  normalizeMaxBreadth: 500,

  // Max characters for string values before truncation
  maxValueLength: 500,

  // Send client-side outcome reports to Sentry (default: true)
  sendClientReports: true,
});
```

## Integrations

```javascript
import * as Sentry from "@sentry/browser";

Sentry.init({
  integrations: [
    // Performance monitoring
    Sentry.browserTracingIntegration(),

    // Session replay
    Sentry.replayIntegration(),

    // User feedback widget
    Sentry.feedbackIntegration({ colorScheme: "system" }),

    // HTTP client errors (4xx, 5xx as events)
    Sentry.httpClientIntegration(),

    // Capture console.error as events
    Sentry.captureConsoleIntegration({ levels: ["error", "warn"] }),

    // Report only errors with stack traces from specific URLs
    Sentry.reportingObserverIntegration(),
  ],

  // Disable all default integrations (advanced)
  // defaultIntegrations: false,
});
```

## Logs (Experimental)

```javascript
Sentry.init({
  enableLogs: true,  // default: false

  beforeSendLog(log) {
    // Drop debug logs
    if (log.level === "debug") return null;
    return log;
  },
});

// Usage
Sentry.logger.info("User completed onboarding");
Sentry.logger.warn("Slow query", { duration: 3500 });
Sentry.logger.error("Validation failed", { field: "email" });
```

## Common Production Configuration

```javascript
// Recommended production config
Sentry.init({
  dsn: process.env.SENTRY_DSN,
  release: process.env.SENTRY_RELEASE,
  environment: process.env.NODE_ENV,
  sampleRate: 1.0,
  tracesSampleRate: 0.1,
  replaysSessionSampleRate: 0.1,
  replaysOnErrorSampleRate: 1.0,
  ignoreErrors: [
    "ResizeObserver loop limit exceeded",
    /^Loading chunk \d+ failed$/,
    /^Network request failed$/,
  ],
  denyUrls: [/extensions\//i, /^chrome:\/\//i],
  integrations: [
    Sentry.browserTracingIntegration(),
    Sentry.replayIntegration({ maskAllText: true, blockAllMedia: true }),
  ],
});
```
